    97→/// Minimum value
    98→pub fn min(args: Vec<Value>) -> Result<Value, String> {
    99→    if args.is_empty() {
   100→        return Err("min requires at least 1 argument".to_string());
   101→    }
   102→
   103→    let mut min_val = args[0].to_number();
   104→    for arg in &args[1..] {
   105→        let val = arg.to_number();
   106→        if val < min_val {
   107→            min_val = val;
   108→        }
   109→    }
   110→    Ok(Value::Number(min_val))
   111→}
