     6→/// Concatenate strings
     7→pub fn concat(args: Vec<Value>) -> Result<Value, String> {
     8→    let mut result = String::new();
     9→    for arg in args {
    10→        result.push_str(&arg.to_string());
    11→    }
    12→    Ok(Value::String(result))
    13→}
    14→
    15→/// Convert to uppercase
    16→pub fn uppercase(args: Vec<Value>) -> Result<Value, String> {
    17→    if args.is_empty() {
    18→        return Err("uppercase requires 1 argument".to_string());
    19→    }
    20→    Ok(Value::String(args[0].to_string().to_uppercase()))
    21→}
    22→
    23→/// Convert to lowercase
    24→pub fn lowercase(args: Vec<Value>) -> Result<Value, String> {
    25→    if args.is_empty() {
    26→        return Err("lowercase requires 1 argument".to_string());
    27→    }
    28→    Ok(Value::String(args[0].to_string().to_lowercase()))
    29→}
