   134→/// Replace substring occurrences
   135→pub fn replace(args: Vec<Value>) -> Result<Value, String> {
   136→    if args.len() < 3 {
   137→        return Err("replace requires 3 arguments: string, from, to".to_string());
   138→    }
   139→    let s = args[0].to_string();
   140→    let from = args[1].to_string();
   141→    let to = args[2].to_string();
   142→
   143→    Ok(Value::String(s.replace(&from, &to)))
   144→}
   145→
   146→/// Find index of substring
   147→pub fn index_of(args: Vec<Value>) -> Result<Value, String> {
   148→    if args.len() < 2 {
   149→        return Err("index_of requires 2 arguments: string, substring".to_string());
   150→    }
   151→    let s = args[0].to_string();
   152→    let substring = args[1].to_string();
   153→
   154→    match s.find(&substring) {
   155→        Some(idx) => Ok(Value::Number(idx as f64)),
   156→        None => Ok(Value::Number(-1.0))
   157→    }
   158→}
   159→
   160→/// Check if string contains substring
   161→pub fn contains(args: Vec<Value>) -> Result<Value, String> {
   162→    if args.len() < 2 {
   163→        return Err("contains requires 2 arguments: string, substring".to_string());
   164→    }
   165→    let s = args[0].to_string();
   166→    let substring = args[1].to_string();
   167→
   168→    Ok(Value::Bool(s.contains(&substring)))
