   170→
   171→/// Check if string starts with substring
   172→pub fn starts_with(args: Vec<Value>) -> Result<Value, String> {
   173→    if args.len() < 2 {
   174→        return Err("starts_with requires 2 arguments: string, prefix".to_string());
   175→    }
   176→    let s = args[0].to_string();
