   190→    Ok(Value::Bool(s.ends_with(&suffix)))
   191→}
   192→
   193→/// Repeat string n times
   194→pub fn repeat(args: Vec<Value>) -> Result<Value, String> {
   195→    if args.len() < 2 {
   196→        return Err("repeat requires 2 arguments: string, count".to_string());
   197→    }
   198→    let s = args[0].to_string();
   199→    let count = args[1].to_number() as usize;
