     5→use std::fs::{File, OpenOptions};
     6→use std::io::{self, BufReader, BufRead, Read, Write};
     7→use std::collections::HashMap;
     8→
     9→// Global file handles for tracking open files
    10→thread_local! {
    11→    static FILE_HANDLES: std::cell::RefCell<HashMap<String, Box<dyn std::any::Any>>> =
    12→        std::cell::RefCell::new(HashMap::new());
    13→}
    14→
    15→/// Print arguments without newline
    16→pub fn print(args: Vec<Value>) -> Result<Value, String> {
    17→    for arg in args {
    18→        print!("{}", arg);
    19→    }
    20→    Ok(Value::Null)
    21→}
    22→
    23→/// Print arguments with newline
    24→pub fn println(args: Vec<Value>) -> Result<Value, String> {
    25→    for arg in args {
    26→        println!("{}", arg);
    27→    }
    28→    Ok(Value::Null)
    29→}
    30→
    31→/// Read a line from stdin
    32→pub fn input(_args: Vec<Value>) -> Result<Value, String> {
    33→    let mut buffer = String::new();
    34→    io::stdin().read_line(&mut buffer)
    35→        .map_err(|e| format!("Input error: {}", e))?;
    36→    Ok(Value::String(buffer.trim().to_string()))
    37→}
    38→
    39→/// Open a file for reading (mode="r") or writing (mode="w")
    40→pub fn open(args: Vec<Value>) -> Result<Value, String> {
    41→    if args.len() < 2 {
    42→        return Err("open requires 2 arguments: filename, mode".to_string());
    43→    }
    44→
    45→    let filename = args[0].to_string();
    46→    let mode = args[1].to_string();
    47→
    48→    match mode.as_str() {
    49→        "r" => {
    50→            match File::open(&filename) {
    51→                Ok(file) => {
    52→                    let reader = Box::new(BufReader::new(file)) as Box<dyn std::any::Any>;
    53→                    FILE_HANDLES.with(|fh| {
    54→                        fh.borrow_mut().insert(filename.clone(), reader);
    55→                    });
    56→                    Ok(Value::String(filename))
    57→                }
    58→                Err(e) => Err(format!("Cannot open file: {}", e))
    59→            }
    60→        }
    61→        "w" => {
    62→            match OpenOptions::new()
    63→                .write(true)
    64→                .create(true)
    65→                .truncate(true)
    66→                .open(&filename)
    67→            {
    68→                Ok(file) => {
    69→                    let writer = Box::new(file) as Box<dyn std::any::Any>;
    70→                    FILE_HANDLES.with(|fh| {
    71→                        fh.borrow_mut().insert(filename.clone(), writer);
    72→                    });
    73→                    Ok(Value::String(filename))
    74→                }
    75→                Err(e) => Err(format!("Cannot create file: {}", e))
    76→            }
    77→        }
    78→        _ => Err(format!("Unknown mode: {}", mode))
    79→    }
    80→}
    81→
    82→/// Close a file handle
    83→pub fn close(args: Vec<Value>) -> Result<Value, String> {
    84→    if args.is_empty() {
    85→        return Err("close requires filename argument".to_string());
    86→    }
    87→
    88→    let filename = args[0].to_string();
    89→    FILE_HANDLES.with(|fh| {
    90→        fh.borrow_mut().remove(&filename);
    91→    });
    92→    Ok(Value::Null)
    93→}
    94→
    95→/// Read entire file content as string
    96→pub fn read_file(args: Vec<Value>) -> Result<Value, String> {
    97→    if args.is_empty() {
    98→        return Err("read_file requires filename argument".to_string());
    99→    }
   100→
   101→    let filename = args[0].to_string();
   102→    match std::fs::read_to_string(&filename) {
   103→        Ok(content) => Ok(Value::String(content)),
   104→        Err(e) => Err(format!("Cannot read file: {}", e))
   105→    }
   106→}
   107→
   108→/// Write string to file
   109→pub fn write_file(args: Vec<Value>) -> Result<Value, String> {
   110→    if args.len() < 2 {
   111→        return Err("write_file requires 2 arguments: filename, content".to_string());
   112→    }
   113→
   114→    let filename = args[0].to_string();
   115→    let content = args[1].to_string();
   116→
   117→    match std::fs::write(&filename, &content) {
   118→        Ok(_) => Ok(Value::Number(content.len() as f64)),
   119→        Err(e) => Err(format!("Cannot write file: {}", e))
   120→    }
   121→}
   122→
   123→/// Append string to file
   124→pub fn append_file(args: Vec<Value>) -> Result<Value, String> {
   125→    if args.len() < 2 {
   126→        return Err("append_file requires 2 arguments: filename, content".to_string());
   127→    }
   128→
   129→    let filename = args[0].to_string();
   130→    let content = args[1].to_string();
   131→
   132→    match OpenOptions::new()
   133→        .create(true)
   134→        .append(true)
   135→        .open(&filename)
   136→    {
   137→        Ok(mut file) => {
   138→            match file.write_all(content.as_bytes()) {
   139→                Ok(_) => Ok(Value::Number(content.len() as f64)),
   140→                Err(e) => Err(format!("Write error: {}", e))
   141→            }
   142→        }
   143→        Err(e) => Err(format!("Cannot open file: {}", e))
   144→    }
   145→}
   146→
   147→/// Check if file exists
   148→pub fn file_exists(args: Vec<Value>) -> Result<Value, String> {
   149→    if args.is_empty() {
   150→        return Err("file_exists requires filename argument".to_string());
   151→    }
   152→
   153→    let filename = args[0].to_string();
   154→    Ok(Value::Bool(std::path::Path::new(&filename).exists()))
   155→}
   156→
   157→/// Delete a file
   158→pub fn delete_file(args: Vec<Value>) -> Result<Value, String> {
   159→    if args.is_empty() {
   160→        return Err("delete_file requires filename argument".to_string());
   161→    }
   162→
   163→    let filename = args[0].to_string();
   164→    match std::fs::remove_file(&filename) {
   165→        Ok(_) => Ok(Value::Null),
   166→        Err(e) => Err(format!("Cannot delete file: {}", e))
   167→    }
   168→}
   169→
   170→/// Get file size in bytes
   171→pub fn file_size(args: Vec<Value>) -> Result<Value, String> {
   172→    if args.is_empty() {
   173→        return Err("file_size requires filename argument".to_string());
   174→    }
   175→
   176→    let filename = args[0].to_string();
   177→    match std::fs::metadata(&filename) {
   178→        Ok(metadata) => Ok(Value::Number(metadata.len() as f64)),
   179→        Err(e) => Err(format!("Cannot get file size: {}", e))
   180→    }
   181→}
   182→
   183→/// List files in directory
   184→pub fn list_dir(args: Vec<Value>) -> Result<Value, String> {
   185→    if args.is_empty() {
   186→        return Err("list_dir requires directory path argument".to_string());
   187→    }
   188→
   189→    let path = args[0].to_string();
   190→    match std::fs::read_dir(&path) {
   191→        Ok(entries) => {
   192→            let mut files = Vec::new();
   193→            for entry in entries {
   194→                if let Ok(entry) = entry {
   195→                    if let Some(name) = entry.file_name().to_str() {
   196→                        files.push(Value::String(name.to_string()));
   197→                    }
   198→                }
   199→            }
   200→            Ok(Value::array(files))
   201→        }
   202→        Err(e) => Err(format!("Cannot list directory: {}", e))
   203→    }
   204→}
   205→
   206→/// Create a directory
   207→pub fn mkdir(args: Vec<Value>) -> Result<Value, String> {
   208→    if args.is_empty() {
   209→        return Err("mkdir requires directory path argument".to_string());
   210→    }
   211→
   212→    let path = args[0].to_string();
   213→    match std::fs::create_dir_all(&path) {
   214→        Ok(_) => Ok(Value::Null),
   215→        Err(e) => Err(format!("Cannot create directory: {}", e))
   216→    }
   217→}
   218→
   219→/// Print to stderr
   220→pub fn eprint(args: Vec<Value>) -> Result<Value, String> {
   221→    for arg in args {
   222→        eprint!("{}", arg);
   223→    }
   224→    Ok(Value::Null)
   225→}
   226→
   227→/// Print to stderr with newline
   228→pub fn eprintln(args: Vec<Value>) -> Result<Value, String> {
   229→    for arg in args {
   230→        eprintln!("{}", arg);
   231→    }
   232→    Ok(Value::Null)
   233→}
