     1→// Array Functions (12)
     2→// Array manipulation and operations
     3→
     4→use crate::core::Value;
     5→
     6→/// Get array length
     7→pub fn length(args: Vec<Value>) -> Result<Value, String> {
     8→    if args.is_empty() {
     9→        return Err("length requires 1 argument".to_string());
    10→    }
    11→
    12→    match &args[0] {
    13→        Value::Array(arr) => {
    14→            Ok(Value::Number(arr.borrow().len() as f64))
    15→        }
    16→        _ => Err("Argument must be an array".to_string())
    17→    }
    18→}
    19→
    20→/// Push element to array
    21→pub fn push(args: Vec<Value>) -> Result<Value, String> {
    22→    if args.len() < 2 {
    23→        return Err("push requires 2 arguments: array, value".to_string());
    24→    }
    25→
    26→    match &args[0] {
    27→        Value::Array(arr) => {
    28→            arr.borrow_mut().push(args[1].clone());
    29→            Ok(Value::Number(arr.borrow().len() as f64))
    30→        }
    31→        _ => Err("First argument must be an array".to_string())
    32→    }
    33→}
    34→
    35→/// Pop element from array
    36→pub fn pop(args: Vec<Value>) -> Result<Value, String> {
    37→    if args.is_empty() {
    38→        return Err("pop requires 1 argument".to_string());
    39→    }
    40→
    41→    match &args[0] {
    42→        Value::Array(arr) => {
    43→            match arr.borrow_mut().pop() {
    44→                Some(value) => Ok(value),
    45→                None => Ok(Value::Null)
    46→            }
    47→        }
    48→        _ => Err("Argument must be an array".to_string())
    49→    }
    50→}
    51→
    52→/// Get element at index
    53→pub fn get(args: Vec<Value>) -> Result<Value, String> {
    54→    if args.len() < 2 {
    55→        return Err("get requires 2 arguments: array, index".to_string());
    56→    }
    57→
    58→    match &args[0] {
    59→        Value::Array(arr) => {
    60→            let index = args[1].to_number() as usize;
    61→            let arr_ref = arr.borrow();
    62→            if index < arr_ref.len() {
    63→                Ok(arr_ref[index].clone())
    64→            } else {
    65→                Ok(Value::Null)
    66→            }
    67→        }
    68→        _ => Err("First argument must be an array".to_string())
    69→    }
    70→}
    71→
    72→/// Set element at index
    73→pub fn set(args: Vec<Value>) -> Result<Value, String> {
    74→    if args.len() < 3 {
    75→        return Err("set requires 3 arguments: array, index, value".to_string());
    76→    }
    77→
    78→    match &args[0] {
    79→        Value::Array(arr) => {
    80→            let index = args[1].to_number() as usize;
    81→            let mut arr_mut = arr.borrow_mut();
    82→            if index < arr_mut.len() {
    83→                arr_mut[index] = args[2].clone();
    84→                Ok(Value::Null)
    85→            } else {
    86→                Err("Index out of bounds".to_string())
    87→            }
    88→        }
    89→        _ => Err("First argument must be an array".to_string())
    90→    }
    91→}
    92→
    93→/// Slice array from start to end
    94→pub fn slice(args: Vec<Value>) -> Result<Value, String> {
    95→    if args.len() < 3 {
    96→        return Err("slice requires 3 arguments: array, start, end".to_string());
    97→    }
    98→
    99→    match &args[0] {
   100→        Value::Array(arr) => {
   101→            let start = args[1].to_number() as usize;
   102→            let end = args[2].to_number() as usize;
   103→            let arr_ref = arr.borrow();
   104→
   105→            if start >= arr_ref.len() || end > arr_ref.len() || start > end {
   106→                return Err("Invalid slice range".to_string());
   107→            }
   108→
   109→            let sliced: Vec<Value> = arr_ref[start..end].to_vec();
   110→            Ok(Value::array(sliced))
   111→        }
   112→        _ => Err("First argument must be an array".to_string())
   113→    }
   114→}
