   171→/// Sort array (numeric/lexical)
   172→pub fn sort(args: Vec<Value>) -> Result<Value, String> {
   173→    if args.is_empty() {
   174→        return Err("sort requires 1 argument".to_string());
   175→    }
   176→
   177→    match &args[0] {
   178→        Value::Array(arr) => {
   179→            arr.borrow_mut().sort_by(|a, b| {
   180→                a.to_number()
   181→                    .partial_cmp(&b.to_number())
   182→                    .unwrap_or(std::cmp::Ordering::Equal)
   183→            });
   184→            Ok(Value::Null)
   185→        }
   186→        _ => Err("Argument must be an array".to_string())
   187→    }
   188→}
   189→
   190→/// Join array elements into string
   191→pub fn join(args: Vec<Value>) -> Result<Value, String> {
   192→    if args.len() < 2 {
   193→        return Err("join requires 2 arguments: array, delimiter".to_string());
   194→    }
   195→
   196→    match &args[0] {
   197→        Value::Array(arr) => {
   198→            let delimiter = args[1].to_string();
   199→            let arr_ref = arr.borrow();
   200→            let parts: Vec<String> = arr_ref
   201→                .iter()
   202→                .map(|v| v.to_string())
   203→                .collect();
   204→            Ok(Value::String(parts.join(&delimiter)))
   205→        }
   206→        _ => Err("First argument must be an array".to_string())
   207→    }
   208→}
