     8→/// Simple hash function (using DefaultHasher)
     9→pub fn hash(args: Vec<Value>) -> Result<Value, String> {
    10→    if args.is_empty() {
    11→        return Err("hash requires 1 argument".to_string());
    12→    }
    13→
    14→    let data = args[0].to_string();
    15→    let mut hasher = DefaultHasher::new();
    16→    data.hash(&mut hasher);
    17→    let hash_value = hasher.finish();
    18→
    19→    Ok(Value::String(format!("{:x}", hash_value)))
    20→}
