    85→/// Base64 encoding
    86→pub fn base64_encode(args: Vec<Value>) -> Result<Value, String> {
    87→    if args.is_empty() {
    88→        return Err("base64_encode requires 1 argument".to_string());
    89→    }
    90→
    91→    let data = args[0].to_string();
    92→    const CHARSET: &[u8] = b"ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/";
    93→
    94→    let bytes = data.as_bytes();
    95→    let mut result = String::new();
    96→
    97→    for chunk in bytes.chunks(3) {
    98→        let b1 = chunk[0];
    99→        let b2 = chunk.get(1).copied().unwrap_or(0);
   100→        let b3 = chunk.get(2).copied().unwrap_or(0);
   101→
   102→        let n = ((b1 as u32) << 16) | ((b2 as u32) << 8) | (b3 as u32);
   103→
   104→        result.push(CHARSET[((n >> 18) & 63) as usize] as char);
   105→        result.push(CHARSET[((n >> 12) & 63) as usize] as char);
   106→
   107→        if chunk.len() > 1 {
   108→            result.push(CHARSET[((n >> 6) & 63) as usize] as char);
   109→        } else {
   110→            result.push('=');
   111→        }
   112→
   113→        if chunk.len() > 2 {
   114→            result.push(CHARSET[(n & 63) as usize] as char);
   115→        } else {
   116→            result.push('=');
   117→        }
   118→    }
   119→
   120→    Ok(Value::String(result))
   121→}
   122→
   123→/// Base64 decoding
   124→pub fn base64_decode(args: Vec<Value>) -> Result<Value, String> {
   125→    if args.is_empty() {
   126→        return Err("base64_decode requires 1 argument".to_string());
   127→    }
   128→
   129→    let data = args[0].to_string();
   130→
   131→    // Simple base64 decoder
   132→    let charset = "ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/";
   133→    let mut result = Vec::new();
   134→
   135→    for chunk in data.as_bytes().chunks(4) {
   136→        if chunk.len() < 2 {
   137→            break;
   138→        }
   139→
   140→        let mut n: u32 = 0;
   141→        for (i, &c) in chunk.iter().enumerate() {
   142→            if c == b'=' {
   143→                break;
   144→            }
   145→
   146→            if let Some(idx) = charset.find(c as char) {
   147→                n = (n << 6) | (idx as u32);
   148→            }
   149→        }
   150→
   151→        let shift = match chunk.len() {
   152→            2 => 4,
   153→            3 => 10,
   154→            _ => 16,
   155→        };
   156→
   157→        for i in (0..shift).step_by(8) {
   158→            result.push(((n >> i) & 0xFF) as u8);
   159→        }
   160→    }
   161→
   162→    match String::from_utf8(result) {
   163→        Ok(s) => Ok(Value::String(s)),
   164→        Err(_) => Err("Invalid UTF-8 in decoded data".to_string())
   165→    }
   166→}
