   168→/// Hex encoding
   169→pub fn hex_encode(args: Vec<Value>) -> Result<Value, String> {
   170→    if args.is_empty() {
   171→        return Err("hex_encode requires 1 argument".to_string());
   172→    }
   173→
   174→    let data = args[0].to_string();
   175→    let hex: String = data
   176→        .as_bytes()
   177→        .iter()
   178→        .map(|b| format!("{:02x}", b))
   179→        .collect();
   180→
   181→    Ok(Value::String(hex))
   182→}
