     6→/// Parse JSON string to Value
     7→pub fn parse(args: Vec<Value>) -> Result<Value, String> {
     8→    if args.is_empty() {
     9→        return Err("parse requires 1 argument".to_string());
    10→    }
    11→
    12→    let json_str = args[0].to_string();
    13→    parse_json(&json_str)
    14→}
