    16→/// Convert Value to JSON string
    17→pub fn stringify(args: Vec<Value>) -> Result<Value, String> {
    18→    if args.is_empty() {
    19→        return Err("stringify requires 1 argument".to_string());
    20→    }
    21→
    22→    let json_str = value_to_json(&args[0]);
    23→    Ok(Value::String(json_str))
    24→}
