    32→    let json_str = value_to_json_pretty(&args[0], 0);
    33→    Ok(Value::String(json_str))
    34→}
    35→
    36→/// Load JSON from string (alias for parse)
    37→pub fn load(args: Vec<Value>) -> Result<Value, String> {
    38→    parse(args)
    39→}
    40→
    41→/// Validate JSON string
    42→pub fn validate(args: Vec<Value>) -> Result<Value, String> {
    43→    if args.is_empty() {
    44→        return Err("validate requires 1 argument".to_string());
    45→    }
    46→
    47→    let json_str = args[0].to_string();
    48→    match parse_json(&json_str) {
    49→        Ok(_) => Ok(Value::Bool(true)),
    50→        Err(_) => Ok(Value::Bool(false))
    51→    }
    52→}
    53→
    54→// Helper functions
    55→
    56→fn parse_json(s: &str) -> Result<Value, String> {
    57→    let trimmed = s.trim();
    58→
    59→    if trimmed.is_empty() {
    60→        return Err("Empty JSON string".to_string());
    61→    }
    62→
    63→    let (value, _) = parse_value(trimmed)?;
    64→    Ok(value)
    65→}
    66→
    67→fn parse_value(s: &str) -> Result<(Value, &str), String> {
    68→    let trimmed = skip_whitespace(s);
    69→
    70→    match trimmed.chars().next() {
    71→        Some('"') => parse_string(trimmed),
    72→        Some('{') => parse_object(trimmed),
    73→        Some('[') => parse_array(trimmed),
    74→        Some('t') | Some('f') => parse_bool(trimmed),
    75→        Some('n') => parse_null(trimmed),
    76→        Some(c) if c == '-' || c.is_ascii_digit() => parse_number(trimmed),
    77→        _ => Err("Invalid JSON value".to_string()),
    78→    }
    79→}
    80→
    81→fn parse_string(s: &str) -> Result<(Value, &str), String> {
    82→    if !s.starts_with('"') {
    83→        return Err("Expected string".to_string());
    84→    }
    85→
    86→    let mut result = String::new();
    87→    let mut chars = s[1..].chars();
    88→    let mut remaining = &s[1..];
    89→
    90→    loop {
    91→        match chars.next() {
    92→            Some('"') => {
    93→                let rest = remaining.split('"').nth(1).unwrap_or("");
    94→                return Ok((Value::String(result), rest));
    95→            }
    96→            Some('\\') => {
    97→                if let Some(c) = chars.next() {
    98→                    match c {
    99→                        'n' => result.push('\n'),
   100→                        't' => result.push('\t'),
   101→                        'r' => result.push('\r'),
   102→                        '\\' => result.push('\\'),
   103→                        '"' => result.push('"'),
   104→                        _ => {
   105→                            result.push('\\');
   106→                            result.push(c);
   107→                        }
   108→                    }
   109→                }
   110→            }
   111→            Some(c) => result.push(c),
   112→            None => return Err("Unterminated string".to_string()),
   113→        }
   114→    }
   115→}
   116→
   117→fn parse_number(s: &str) -> Result<(Value, &str), String> {
   118→    let mut end = 0;
   119→    let mut has_dot = false;
   120→
   121→    for (i, c) in s.chars().enumerate() {
   122→        match c {
   123→            '-' if i == 0 => {}
   124→            '0'..='9' => {}
   125→            '.' if !has_dot => has_dot = true,
   126→            'e' | 'E' => {
   127→                end = i + 1;
   128→                if i + 1 < s.len() && (s.chars().nth(i + 1) == Some('+') || s.chars().nth(i + 1) == Some('-')) {
   129→                    end += 1;
   130→                }
   131→                continue;
   132→            }
   133→            _ => {
   134→                end = i;
   135→                break;
   136→            }
   137→        }
   138→        end = i + 1;
   139→    }
   140→
   141→    let num_str = &s[..end];
   142→    match num_str.parse::<f64>() {
   143→        Ok(n) => Ok((Value::Number(n), &s[end..])),
   144→        Err(_) => Err("Invalid number".to_string()),
   145→    }
   146→}
   147→
   148→fn parse_bool(s: &str) -> Result<(Value, &str), String> {
   149→    if s.starts_with("true") {
   150→        Ok((Value::Bool(true), &s[4..]))
   151→    } else if s.starts_with("false") {
   152→        Ok((Value::Bool(false), &s[5..]))
   153→    } else {
   154→        Err("Invalid boolean".to_string())
   155→    }
   156→}
   157→
   158→fn parse_null(s: &str) -> Result<(Value, &str), String> {
   159→    if s.starts_with("null") {
   160→        Ok((Value::Null, &s[4..]))
   161→    } else {
   162→        Err("Invalid null".to_string())
   163→    }
   164→}
   165→
   166→fn parse_array(s: &str) -> Result<(Value, &str), String> {
   167→    if !s.starts_with('[') {
   168→        return Err("Expected array".to_string());
   169→    }
   170→
   171→    let mut elements = Vec::new();
   172→    let mut remaining = skip_whitespace(&s[1..]);
   173→
   174→    if remaining.starts_with(']') {
   175→        return Ok((Value::array(elements), &remaining[1..]));
   176→    }
   177→
   178→    loop {
   179→        let (value, rest) = parse_value(remaining)?;
   180→        elements.push(value);
   181→        remaining = skip_whitespace(rest);
   182→
   183→        if remaining.starts_with(',') {
   184→            remaining = skip_whitespace(&remaining[1..]);
   185→        } else if remaining.starts_with(']') {
   186→            return Ok((Value::array(elements), &remaining[1..]));
   187→        } else {
   188→            return Err("Invalid array format".to_string());
   189→        }
   190→    }
   191→}
   192→
   193→fn parse_object(s: &str) -> Result<(Value, &str), String> {
   194→    if !s.starts_with('{') {
   195→        return Err("Expected object".to_string());
   196→    }
   197→
   198→    let obj = Value::empty_object();
   199→    let mut remaining = skip_whitespace(&s[1..]);
   200→
   201→    if remaining.starts_with('}') {
   202→        return Ok((obj, &remaining[1..]));
   203→    }
   204→
   205→    loop {
   206→        remaining = skip_whitespace(remaining);
   207→
   208→        // Parse key
   209→        if !remaining.starts_with('"') {
   210→            return Err("Expected string key in object".to_string());
   211→        }
   212→
   213→        let (Value::String(key), rest) = parse_string(remaining)? else {
   214→            return Err("Invalid object key".to_string());
   215→        };
   216→
   217→        remaining = skip_whitespace(rest);
   218→        if !remaining.starts_with(':') {
   219→            return Err("Expected ':' in object".to_string());
   220→        }
   221→
   222→        remaining = skip_whitespace(&remaining[1..]);
   223→
   224→        // Parse value
   225→        let (value, rest) = parse_value(remaining)?;
   226→        obj.set_property(key, value)
   227→            .map_err(|e| format!("Object set error: {}", e))?;
   228→
   229→        remaining = skip_whitespace(rest);
   230→
   231→        if remaining.starts_with(',') {
   232→            remaining = skip_whitespace(&remaining[1..]);
   233→        } else if remaining.starts_with('}') {
   234→            return Ok((obj, &remaining[1..]));
   235→        } else {
   236→            return Err("Invalid object format".to_string());
   237→        }
   238→    }
   239→}
   240→
   241→fn skip_whitespace(s: &str) -> &str {
   242→    s.trim_start()
   243→}
   244→
   245→fn value_to_json(value: &Value) -> String {
   246→    match value {
   247→        Value::Null => "null".to_string(),
   248→        Value::Bool(b) => b.to_string(),
   249→        Value::Number(n) => {
   250→            if n.fract() == 0.0 {
   251→                format!("{:.0}", n)
   252→            } else {
   253→                n.to_string()
   254→            }
   255→        }
   256→        Value::String(s) => format!("\"{}\"", s.replace("\"", "\\\"").replace("\n", "\\n")),
   257→        Value::Array(arr) => {
   258→            let elements: Vec<String> = arr.borrow()
   259→                .iter()
   260→                .map(value_to_json)
   261→                .collect();
   262→            format!("[{}]", elements.join(","))
   263→        }
   264→        Value::Object(obj) => {
   265→            let obj_ref = obj.borrow();
   266→            let mut pairs: Vec<String> = Vec::new();
   267→
   268→            for (key, val) in obj_ref.iter() {
   269→                let json_key = format!("\"{}\"", key.replace("\"", "\\\""));
   270→                let json_val = value_to_json(val);
   271→                pairs.push(format!("{}:{}", json_key, json_val));
   272→            }
   273→
   274→            format!("{{{}}}", pairs.join(","))
   275→        }
   276→        _ => "null".to_string(),
   277→    }
   278→}
   279→
   280→fn value_to_json_pretty(value: &Value, indent: usize) -> String {
   281→    let indent_str = " ".repeat(indent);
   282→    let next_indent_str = " ".repeat(indent + 2);
   283→
   284→    match value {
   285→        Value::Null => "null".to_string(),
   286→        Value::Bool(b) => b.to_string(),
   287→        Value::Number(n) => {
   288→            if n.fract() == 0.0 {
   289→                format!("{:.0}", n)
   290→            } else {
   291→                n.to_string()
   292→            }
   293→        }
   294→        Value::String(s) => format!("\"{}\"", s.replace("\"", "\\\"").replace("\n", "\\n")),
   295→        Value::Array(arr) => {
   296→            let arr_ref = arr.borrow();
   297→            if arr_ref.is_empty() {
   298→                "[]".to_string()
   299→            } else {
   300→                let elements: Vec<String> = arr_ref
   301→                    .iter()
   302→                    .map(|v| format!("{}{}", next_indent_str, value_to_json_pretty(v, indent + 2)))
   303→                    .collect();
   304→                format!("[\n{}\n{}]", elements.join(",\n"), indent_str)
   305→            }
   306→        }
   307→        Value::Object(obj) => {
   308→            let obj_ref = obj.borrow();
   309→            if obj_ref.is_empty() {
   310→                "{}".to_string()
   311→            } else {
   312→                let mut pairs: Vec<String> = Vec::new();
   313→                for (key, val) in obj_ref.iter() {
   314→                    let json_key = format!("\"{}\"", key);
   315→                    let json_val = value_to_json_pretty(val, indent + 2);
   316→                    pairs.push(format!("{}{}: {}", next_indent_str, json_key, json_val));
   317→                }
   318→                format!("{{\n{}\n{}}}", pairs.join(",\n"), indent_str)
   319→            }
   320→        }
   321→        _ => "null".to_string(),
   322→    }
   323→}
