     1→/**
     2→ * FreeLang v4 StdLib — String Functions (13개)
     3→ *
     4→ * 1.  len(s)                → i32          문자 길이
     5→ * 2.  upper(s)              → str          대문자 변환
     6→ * 3.  lower(s)              → str          소문자 변환
     7→ * 4.  trim(s)               → str          앞뒤 공백 제거
     8→ * 5.  split(s, sep)         → arr[str]     구분자로 분리
     9→ * 6.  join(arr, sep)        → str          배열 → 문자열
    10→ * 7.  contains(s, sub)      → bool         부분 문자열 포함 여부
    11→ * 8.  starts_with(s, pre)   → bool         접두사 확인
    12→ * 9.  ends_with(s, suf)     → bool         접미사 확인
    13→ * 10. replace(s, from, to)  → str          치환 (첫 번째)
    14→ * 11. replace_all(s, f, t)  → str          치환 (전체)
    15→ * 12. slice(s, start, end)  → str          부분 문자열
    16→ * 13. repeat(s, n)          → str          반복
    17→ * 14. index_of(s, sub)      → i32          위치 탐색 (-1 = 없음)
    18→ */
    19→
    20→import { Value, V, assertStr, assertI32, assertArr } from "./types";
    21→
    22→// ============================================================
    23→// 1. len
    24→// ============================================================
    25→
    26→export function str_len(s: Value): Value {
    27→  return V.i32(assertStr(s, "len").length);
    28→}
    29→
    30→// ============================================================
    31→// 2. upper
    32→// ============================================================
    33→
    34→export function str_upper(s: Value): Value {
    35→  return V.str(assertStr(s, "upper").toUpperCase());
    36→}
    37→
    38→// ============================================================
    39→// 3. lower
    40→// ============================================================
    41→
    42→export function str_lower(s: Value): Value {
    43→  return V.str(assertStr(s, "lower").toLowerCase());
    44→}
    45→
    46→// ============================================================
    47→// 4. trim
    48→// ============================================================
    49→
    50→export function str_trim(s: Value): Value {
    51→  return V.str(assertStr(s, "trim").trim());
    52→}
    53→
    54→// ============================================================
    55→// 5. split
    56→// ============================================================
    57→
    58→export function str_split(s: Value, sep: Value): Value {
    59→  const str = assertStr(s, "split");
    60→  const delim = assertStr(sep, "split");
    61→  const parts = str.split(delim).map((p) => V.str(p));
    62→  return V.arr(parts);
    63→}
    64→
    65→// ============================================================
    66→// 6. join
    67→// ============================================================
    68→
    69→export function str_join(arr: Value, sep: Value): Value {
    70→  const els  = assertArr(arr, "join");
    71→  const delim = assertStr(sep, "join");
    72→  const strs = els.map((e) => assertStr(e, "join"));
    73→  return V.str(strs.join(delim));
    74→}
    75→
    76→// ============================================================
    77→// 7. contains
    78→// ============================================================
    79→
    80→export function str_contains(s: Value, sub: Value): Value {
    81→  return V.bool(assertStr(s, "contains").includes(assertStr(sub, "contains")));
    82→}
    83→
    84→// ============================================================
    85→// 8. starts_with
    86→// ============================================================
    87→
    88→export function str_starts_with(s: Value, prefix: Value): Value {
    89→  return V.bool(assertStr(s, "starts_with").startsWith(assertStr(prefix, "starts_with")));
    90→}
    91→
    92→// ============================================================
    93→// 9. ends_with
    94→// ============================================================
    95→
    96→export function str_ends_with(s: Value, suffix: Value): Value {
    97→  return V.bool(assertStr(s, "ends_with").endsWith(assertStr(suffix, "ends_with")));
    98→}
    99→
   100→// ============================================================
   101→// 10. replace (첫 번째만)
   102→// ============================================================
   103→
   104→export function str_replace(s: Value, from: Value, to: Value): Value {
   105→  const str  = assertStr(s, "replace");
   106→  const f    = assertStr(from, "replace");
   107→  const t    = assertStr(to, "replace");
   108→  return V.str(str.replace(f, t));
   109→}
   110→
   111→// ============================================================
   112→// 11. replace_all (전체)
   113→// ============================================================
   114→
   115→export function str_replace_all(s: Value, from: Value, to: Value): Value {
   116→  const str = assertStr(s, "replace_all");
   117→  const f   = assertStr(from, "replace_all");
   118→  const t   = assertStr(to, "replace_all");
   119→  return V.str(str.replaceAll(f, t));
   120→}
   121→
   122→// ============================================================
   123→// 12. slice
   124→// ============================================================
   125→
   126→export function str_slice(s: Value, start: Value, end: Value): Value {
   127→  const str = assertStr(s, "slice");
   128→  const st  = assertI32(start, "slice");
   129→  const en  = assertI32(end, "slice");
   130→  // 음수 인덱스 지원: Python 스타일
   131→  const len  = str.length;
   132→  const normSt = st < 0 ? Math.max(0, len + st) : Math.min(st, len);
   133→  const normEn = en < 0 ? Math.max(0, len + en) : Math.min(en, len);
   134→  return V.str(str.slice(normSt, normEn));
   135→}
   136→
   137→// ============================================================
   138→// 13. repeat
   139→// ============================================================
   140→
   141→export function str_repeat(s: Value, n: Value): Value {
   142→  const str = assertStr(s, "repeat");
   143→  const cnt = assertI32(n, "repeat");
   144→  if (cnt < 0) throw new RangeError("repeat: 음수 반복 횟수");
   145→  return V.str(str.repeat(cnt));
   146→}
   147→
   148→// ============================================================
   149→// 14. index_of  (-1 = 없음)
   150→// ============================================================
   151→
   152→export function str_index_of(s: Value, sub: Value): Value {
   153→  return V.i32(assertStr(s, "index_of").indexOf(assertStr(sub, "index_of")));
   154→}
