   156→// ============================================================
   157→// 추가: pad_start, pad_end, char_at, to_chars
   158→// ============================================================
   159→
   160→/** 왼쪽 패딩 */
   161→export function str_pad_start(s: Value, width: Value, fill: Value): Value {
   162→  return V.str(assertStr(s, "pad_start").padStart(assertI32(width, "pad_start"), assertStr(fill, "pad_start")));
   163→}
   164→
   165→/** 오른쪽 패딩 */
   166→export function str_pad_end(s: Value, width: Value, fill: Value): Value {
   167→  return V.str(assertStr(s, "pad_end").padEnd(assertI32(width, "pad_end"), assertStr(fill, "pad_end")));
   168→}
   169→
   170→/** 특정 위치 문자 */
   171→export function str_char_at(s: Value, idx: Value): Value {
   172→  const str = assertStr(s, "char_at");
   173→  const i   = assertI32(idx, "char_at");
   174→  if (i < 0 || i >= str.length) return V.none();
   175→  return V.some(V.str(str[i]));
   176→}
   177→
   178→/** 문자 배열로 분해 */
   179→export function str_to_chars(s: Value): Value {
   180→  return V.arr(assertStr(s, "to_chars").split("").map((c) => V.str(c)));
   181→}
