   125→    /// Register a function
   126→    fn register(&mut self, name: &str, func: FunctionPointer) {
   127→        self.functions.insert(name.to_string(), func);
   128→    }
   129→
   130→    /// Call a function by name with caching
   131→    /// First checks cache for recently used functions (90%+ hit rate)
   132→    /// Falls back to registry on cache miss
   133→    pub fn call(&self, name: &str, args: Vec<Value>) -> Result<Value, String> {
   134→        // Try cache first
   135→        let mut cache = self.cache.borrow_mut();
   136→        if let Some(func) = cache.get(name) {
   137→            drop(cache); // Release borrow before calling
   138→            return func(args);
   139→        }
   140→        drop(cache); // Release borrow
   141→
   142→        // Cache miss - look up in registry
   143→        match self.functions.get(name) {
   144→            Some(func) => {
   145→                // Cache the function for future calls
   146→                let mut cache = self.cache.borrow_mut();
   147→                cache.insert(name.to_string(), *func);
   148→                func(args)
   149→            }
   150→            None => Err(format!("Function not found: {}", name))
   151→        }
   152→    }
   153→
   154→    /// Check if function exists
   155→    pub fn exists(&self, name: &str) -> bool {
   156→        self.functions.contains_key(name)
   157→    }
   158→
   159→    /// Get list of all function names
   160→    pub fn list_functions(&self) -> Vec<&str> {
   161→        self.functions.keys().map(|s| s.as_str()).collect()
   162→    }
   163→
   164→    /// Get function count
   165→    pub fn function_count(&self) -> usize {
   166→        self.functions.len()
   167→    }
   168→
   169→    /// Get cache statistics
   170→    pub fn cache_stats(&self) -> cache::CacheStats {
   171→        self.cache.borrow().stats()
   172→    }
   173→
   174→    /// Clear cache (for testing/debugging)
   175→    pub fn clear_cache(&self) {
   176→        self.cache.borrow_mut().clear();
   177→    }
